 1	import * as React from 'react';
 2	import { t_color_gray_95 as globalBlack1000 } from '@patternfly/react-tokens/dist/js/t_color_gray_95';
 3	import { SVGDefs } from '@patternfly/react-topology';
 4	
 5	interface SvgDropShadowFilterProps {
 6	  // The unique ID that identifies the filter.
 7	  // It is also used to uniquely identify the def entry to prevent duplicates.
 8	  id: string;
 9	  dx?: number;
10	  dy?: number;
11	  stdDeviation?: number;
12	  floodOpacity?: number;
13	  floodColor?: string;
14	}
15	
16	const SvgDropShadowFilter: React.FC<SvgDropShadowFilterProps> = ({
17	  id,
18	  dx = 0,
19	  dy = 1,
20	  stdDeviation = 2,
21	  floodColor = globalBlack1000.value,
22	  floodOpacity = 0.2,
23	}) => {
24	  if (window.navigator.userAgent.includes('Edge')) {
25	    // feDropShadow is not supported by Edge
26	    return (
27	      <SVGDefs id={id}>
28	        <filter
29	          id={id}
30	          x={`-${stdDeviation * 12.5}%`}
31	          y={`-${stdDeviation * 12.5}%`}
32	          width={`${100 + stdDeviation * 25}%`}
33	          height={`${100 + stdDeviation * 25}%`}
34	        >
35	          <feGaussianBlur in="SourceAlpha" stdDeviation={stdDeviation} />
36	          <feOffset dx={dx} dy={dy} result="offsetblur" />
37	          <feFlood floodColor={floodColor} floodOpacity={floodOpacity} />
38	          <feComposite in2="offsetblur" operator="in" />
39	          <feMerge>
40	            <feMergeNode />
41	            <feMergeNode in="SourceGraphic" />
42	          </feMerge>
43	        </filter>
44	      </SVGDefs>
45	    );
46	  }
47	
48	  return (
49	    <SVGDefs id={id}>
50	      <filter
51	        id={id}
52	        x={`-${stdDeviation * 12.5}%`}
53	        y={`-${stdDeviation * 12.5}%`}
54	        width={`${100 + stdDeviation * 25}%`}
55	        height={`${100 + stdDeviation * 25}%`}
56	      >
57	        <feDropShadow
58	          dx={dx}
59	          dy={dy}
60	          stdDeviation={stdDeviation}
61	          floodColor={floodColor}
62	          floodOpacity={floodOpacity}
63	        />
64	      </filter>
65	    </SVGDefs>
66	  );
67	};
68	
69	export default SvgDropShadowFilter;

